-- Vetrica taxonomy library: database-driven species and breeds
-- Source: /Users/toman/Downloads/vetrica_taxonomy_codex_prompt.txt

create extension if not exists pgcrypto;

do $$ begin create type public.species_code as enum ('DOG','CAT','RABBIT','BIRD','OTHER'); exception when duplicate_object then null; end $$;
do $$ begin create type public.custom_taxonomy_type as enum ('SPECIES','BREED'); exception when duplicate_object then null; end $$;
do $$ begin create type public.taxonomy_review_status as enum ('PENDING','APPROVED','REJECTED','MERGED'); exception when duplicate_object then null; end $$;

create table if not exists public.species (
  id uuid primary key default gen_random_uuid(),
  code public.species_code not null unique,
  name_fa text not null,
  name_en text not null,
  is_active boolean not null default true,
  is_custom_allowed boolean not null default false,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.breeds (
  id uuid primary key default gen_random_uuid(),
  species_id uuid not null references public.species(id) on delete cascade,
  code text not null unique,
  name_fa text not null,
  name_en text not null,
  group_fa text,
  group_en text,
  is_active boolean not null default true,
  is_verified boolean not null default true,
  source text not null default 'vetrica_seed',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.custom_pet_taxonomy_entries (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  pet_id uuid references public.pets(id) on delete cascade,
  type public.custom_taxonomy_type not null,
  species_id uuid references public.species(id),
  raw_value text not null,
  normalized_value text,
  review_status public.taxonomy_review_status not null default 'PENDING',
  merged_into_species_id uuid references public.species(id),
  merged_into_breed_id uuid references public.breeds(id),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table public.pets add column if not exists species_id uuid references public.species(id);
alter table public.pets add column if not exists breed_id uuid references public.breeds(id);
alter table public.pets add column if not exists custom_species_text text;
alter table public.pets add column if not exists custom_breed_text text;

create index if not exists species_active_code_idx on public.species(is_active, code);
create index if not exists breeds_species_active_idx on public.breeds(species_id, is_active);
create index if not exists breeds_search_idx on public.breeds using gin (to_tsvector('simple', coalesce(name_fa,'') || ' ' || coalesce(name_en,'') || ' ' || coalesce(group_fa,'') || ' ' || coalesce(group_en,'')));
create index if not exists custom_taxonomy_review_idx on public.custom_pet_taxonomy_entries(review_status, created_at desc);
create index if not exists custom_taxonomy_user_idx on public.custom_pet_taxonomy_entries(user_id, created_at desc);

alter table public.species enable row level security;
alter table public.breeds enable row level security;
alter table public.custom_pet_taxonomy_entries enable row level security;

drop policy if exists "active species readable" on public.species;
create policy "active species readable" on public.species for select to authenticated using (is_active);
drop policy if exists "active breeds readable" on public.breeds;
create policy "active breeds readable" on public.breeds for select to authenticated using (is_active);
drop policy if exists "users view own custom taxonomy" on public.custom_pet_taxonomy_entries;
create policy "users view own custom taxonomy" on public.custom_pet_taxonomy_entries for select to authenticated using (user_id = (select auth.uid()));
drop policy if exists "users create own custom taxonomy" on public.custom_pet_taxonomy_entries;
create policy "users create own custom taxonomy" on public.custom_pet_taxonomy_entries for insert to authenticated with check (user_id = (select auth.uid()));

insert into public.species (code, name_fa, name_en, is_active, is_custom_allowed) values
  ('DOG'::public.species_code, 'سگ', 'Dog', true, false),
  ('CAT'::public.species_code, 'گربه', 'Cat', true, false),
  ('RABBIT'::public.species_code, 'خرگوش', 'Rabbit', true, false),
  ('BIRD'::public.species_code, 'پرنده', 'Bird', true, false),
  ('OTHER'::public.species_code, 'سایر', 'Other', true, true)
on conflict (code) do update set name_fa=excluded.name_fa, name_en=excluded.name_en, is_active=excluded.is_active, is_custom_allowed=excluded.is_custom_allowed, updated_at=now();

