insert into public.breeds (species_id, code, group_en, group_fa, name_fa, name_en, source, is_active, is_verified)
select s.id, bs.code, bs.group_en, bs.group_fa, bs.name_fa, bs.name_en, bs.source, true, true
from breed_seed bs
join public.species s on s.code = bs.species_code
on conflict (code) do update set species_id=excluded.species_id, group_en=excluded.group_en, group_fa=excluded.group_fa, name_fa=excluded.name_fa, name_en=excluded.name_en, source=excluded.source, is_active=true, is_verified=true, updated_at=now();
